/* ── Arrow indicators ────────────────────────────────────────────── */
function Arrows({ type, active }) {
  const col = "rgba(255,255,255,0.82)";
  if (type === "fast") {
    if (active) return (
      <div style={{ width:"44px", height:"44px", borderRadius:"50%", background:"#E8A020", display:"flex", alignItems:"center", justifyContent:"center" }}>
        <svg width="22" height="16" viewBox="0 0 22 16" fill="none">
          <path d="M1 8h7M6 4l4 4-4 4" stroke="white" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
          <path d="M11 8h7M16 4l4 4-4 4" stroke="white" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
      </div>
    );
    return (
      <svg width="40" height="16" viewBox="0 0 40 16" fill="none">
        <path d="M1 8h7M6 4l4 4-4 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M13 8h7M18 4l4 4-4 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    );
  }
  if (type === "triple") return (
    <svg width="56" height="16" viewBox="0 0 56 16" fill="none">
      {[0,16,32].map(x=><path key={x} d={`M${x+1} 8h7M${x+6} 4l4 4-4 4`} stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>)}
    </svg>
  );
  if (type === "dotarrow") return (
    <div style={{ display:"flex", alignItems:"center", gap:"5px" }}>
      {[0,1,2].map(i=><div key={i} style={{ width:"4px", height:"4px", borderRadius:"50%", background:col }}/>)}
      {[0,1].map(i=>(
        <svg key={i} width="16" height="16" viewBox="0 0 16 16" fill="none">
          <path d="M2 8h8M8 4l4 4-4 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
        </svg>
      ))}
    </div>
  );
  if (type === "dots") return (
    <div style={{ display:"flex", alignItems:"center", gap:"5px" }}>
      {[0,1,2,3].map(i=><div key={i} style={{ width:"4px", height:"4px", borderRadius:"50%", background:col }}/>)}
      <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
        <path d="M2 8h8M8 4l4 4-4 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    </div>
  );
  if (type === "double") return (
    <svg width="36" height="16" viewBox="0 0 36 16" fill="none">
      {[0,16].map(x=><path key={x} d={`M${x+1} 8h9M${x+8} 4l4 4-4 4`} stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>)}
    </svg>
  );
  if (type === "single") return (
    <svg width="22" height="16" viewBox="0 0 22 16" fill="none">
      <path d="M1 8h14M12 4l6 4-6 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
  if (type === "quad") return (
    <svg width="72" height="16" viewBox="0 0 72 16" fill="none">
      {[0,16,32,48].map(x=><path key={x} d={`M${x+1} 8h7M${x+6} 4l4 4-4 4`} stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>)}
    </svg>
  );
  if (type === "dotarrow2") return (
    <div style={{ display:"flex", alignItems:"center", gap:"5px" }}>
      <div style={{ width:"4px", height:"4px", borderRadius:"50%", background:col }}/>
      <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
        <path d="M2 8h8M8 4l4 4-4 4" stroke={col} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
      </svg>
    </div>
  );
  return null;
}

/* ── Gradient placeholder (for cards without photo) ─────────────── */
function GradPlaceholder({ active }) {
  return (
    <div style={{
      position:"absolute", inset:0,
      background: active
        ? "linear-gradient(160deg,#7A44C0 0%,#3D1878 100%)"
        : "linear-gradient(160deg,#484060 0%,#1E1A2E 100%)"
    }}/>
  );
}

/* ── Square module card ─────────────────────────────────────────── */
function ModuleCard({ mod, active, onClick }) {
  const imgSrc = mod.key ? IMGS[mod.key] : null;
  const PURPLE = "#5C2D91";
  const GRAY   = "#2C2938";
  const bg     = active ? PURPLE : GRAY;

  return (
    <div onClick={onClick} style={{
      borderRadius:"18px", overflow:"hidden", cursor:"pointer",
      position:"relative",
      aspectRatio:"1 / 1",
      background:bg,
      transition:"transform 0.22s cubic-bezier(.4,0,.2,1), box-shadow 0.22s",
      boxShadow: active ? "0 16px 48px rgba(92,45,145,0.45)" : "0 3px 14px rgba(0,0,0,0.28)",
      transform: active ? "translateY(-5px)" : "translateY(0)",
      display:"flex", flexDirection:"column", justifyContent:"flex-end",
    }}>

      {/* Photo layer */}
      <div style={{ position:"absolute", inset:0 }}>
        {imgSrc ? (
          <img
            src={`data:image/jpeg;base64,${imgSrc}`}
            alt={mod.title}
            style={{
              position:"absolute", inset:0, width:"100%", height:"100%",
              objectFit:"cover", objectPosition:"center top",
              filter: active ? "grayscale(0%) brightness(0.75)" : "grayscale(100%) brightness(0.65)",
              transition:"filter 0.3s ease",
            }}
          />
        ) : <GradPlaceholder active={active}/>}

        {/* Purple tint on active */}
        {active && imgSrc && (
          <div style={{ position:"absolute", inset:0, background:"rgba(80,30,150,0.52)", mixBlendMode:"multiply" }}/>
        )}

        {/* Bottom gradient for text legibility */}
        <div style={{ position:"absolute", bottom:0, left:0, right:0, height:"65%",
          background:`linear-gradient(to top, ${bg} 0%, ${bg}E0 35%, ${bg}80 60%, transparent 100%)`
        }}/>
      </div>

      {/* Text content */}
      <div style={{ position:"relative", zIndex:2, padding:"18px 20px 22px" }}>
        <h3 style={{
          fontFamily:"'Barlow Condensed',Impact,Arial Narrow,sans-serif",
          fontWeight:900,
          fontSize:"clamp(24px,2.4vw,34px)",
          color:"#FFFFFF",
          textTransform:"uppercase",
          letterSpacing:"-0.5px",
          lineHeight:"0.96",
          margin:"0 0 10px 0",
        }}>{mod.title}</h3>
        <p style={{
          color:"rgba(255,255,255,0.68)",
          fontSize:"12px",
          lineHeight:"1.55",
          margin:"0 0 18px 0",
          fontFamily:"'Barlow',system-ui,sans-serif",
        }}>{mod.desc}</p>
        <Arrows type={mod.arrows} active={active}/>
      </div>
    </div>
  );
}

/* ── Animated counter ────────────────────────────────────────────── */
function Counter({ target, duration = 1400 }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting && !started.current) {
        started.current = true;
        const num = parseInt(target.replace(/,/g,""));
        const s = Date.now();
        const tick = () => {
          const p = Math.min((Date.now()-s)/duration, 1);
          setVal(Math.round(num * (1 - Math.pow(1-p,3))));
          if (p < 1) requestAnimationFrame(tick);
        };
        requestAnimationFrame(tick);
      }
    }, { threshold: 0.5 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [target, duration]);
  return <span ref={ref}>{val >= 1000 ? val.toLocaleString("en-US") : val}</span>;
}

